import{_ as e}from"./chunks/fantu-cover.EHiDBquD.js";import{_ as t,o as r,c as o,ai as i}from"./chunks/framework.DyvBZb4W.js";const f=JSON.parse('{"title":"FanTu / 凡途 人物 Mod","description":"","frontmatter":{},"headers":[],"relativePath":"mods/fantu-character/index.md","filePath":"mods/fantu-character/index.md","lastUpdated":1779029223000}'),n={name:"mods/fantu-character/index.md"};function l(s,a,d,c,u,h){return r(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="fantu-凡途-人物-mod" tabindex="-1">FanTu / 凡途 人物 Mod <a class="header-anchor" href="#fantu-凡途-人物-mod" aria-label="Permalink to &quot;FanTu / 凡途 人物 Mod&quot;">​</a></h1><p>FanTu（凡途）是一个面向《杀戮尖塔2》的自定义角色 Mod。它先以“问道客”为第一个可玩人物，同时把底层做成可扩展框架：人物、皮肤、牌包、遗物和药水可以按模块组合。</p><figure><img src="'+e+'" alt="FanTu 凡途人物 Mod 预告封面"><figcaption>每局抽取不同牌包，用有限卡池拼出新的爬塔路线。</figcaption></figure><p>当前版本：<code>v0.1.0</code><br> 发布状态：预告 / 早期可玩<br> 作者：Jason Song<br> 类型：自定义角色 / 随机牌包 / 多流派构筑<br> 是否影响玩法：是，会加入新角色、专属卡牌、牌包、遗物、药水和新的构筑规则。</p><h2 id="核心玩法" tabindex="-1">核心玩法 <a class="header-anchor" href="#核心玩法" aria-label="Permalink to &quot;核心玩法&quot;">​</a></h2><p>FanTu 的核心灵感来自《杀戮尖塔1》的 Packmaster。Packmaster 的特别之处在于：它不是每局都从一个固定大卡池里拿牌，而是在开局时先确定若干个“牌包”。这些牌包各自代表一小组主题牌，本局后续的卡牌奖励主要从这些已选牌包里出现。结果是每局的可用卡池都会变，构筑也会随牌包组合改变。</p><p>FanTu 会把这个思路移植到《杀戮尖塔2》的自定义角色里：角色自带基础牌包，每局再通过随机、三选一或指定配置加入若干流派牌包。本局牌池由这些牌包共同组成，你可以在爬塔前就看到本局可能出现的流派方向，也可以在游戏中查看当前可用卡池。</p><h2 id="目前想让玩家感受到什么" tabindex="-1">目前想让玩家感受到什么 <a class="header-anchor" href="#目前想让玩家感受到什么" aria-label="Permalink to &quot;目前想让玩家感受到什么&quot;">​</a></h2><ul><li><strong>随机但可读</strong>：每局牌包组合不同，但不是完全失控的随机牌海；你能先看懂本局有哪些主题。</li><li><strong>组合感</strong>：修仙、御剑、阵法、符箓、傀儡、炼丹、蛊修、五行、天机、鬼道、体修、星辰等牌包会带来不同资源和收益节奏。</li><li><strong>局内取舍</strong>：牌包决定可遇到的牌，真正成型还要靠路线、奖励选择、升级、遗物和药水继续筛选。</li><li><strong>扩展空间</strong>：长期目标是让 FanTu 成为一个可扩展的牌包角色框架，后续能容纳更多官方或第三方牌包与人物外观。</li></ul><h2 id="和普通角色有什么不同" tabindex="-1">和普通角色有什么不同 <a class="header-anchor" href="#和普通角色有什么不同" aria-label="Permalink to &quot;和普通角色有什么不同&quot;">​</a></h2><p>普通角色通常拥有一个比较稳定的完整卡池；FanTu 更像是“每局先抽出几个小卡池，再围绕它们构筑”。这会让同一个人物在不同开局里有明显不同的决策重心：有的局偏爆发，有的局偏防守循环，有的局会把资源、标记、召唤物、药水或长期成长串在一起。</p><p>这类设计的乐趣不在于背熟一套固定答案，而是在开局看到牌包组合后判断：哪些主题能互相补强，哪些短板需要靠奖励补齐，哪些看似分散的牌可以被遗物或药水重新连接起来。</p><h2 id="当前状态" tabindex="-1">当前状态 <a class="header-anchor" href="#当前状态" aria-label="Permalink to &quot;当前状态&quot;">​</a></h2><ul><li>当前公开信息先作为预告页呈现，具体下载、演示、FAQ 和更新记录会随公开节奏补充。</li><li>当前项目仍在早期打磨阶段，数值、卡池、UI 和美术都可能继续调整。</li><li>需要安装 <code>BaseLib</code>。</li></ul><h2 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h2><ul><li>返回：<a href="/jasonsong-games/mods/">全部 Mod</a></li></ul>',16)])])}const _=t(n,[["render",l]]);export{f as __pageData,_ as default};
